SELECT FROM task_info WHERE 1=1
AND task_type = #{taskType}
AND priority = #{priority}
AND status = #{status}
AND (task_title LIKE CONCAT('%', #{keyword}, '%') OR elderly_name LIKE CONCAT('%', #{keyword}, '%') OR address LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CASE priority WHEN 'URGENT' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'MEDIUM' THEN 3 WHEN 'LOW' THEN 4 END, scheduled_date ASC, created_time DESC

SELECT t.*, d.id as d_id, d.title as d_title, d.attachment_url as d_attachment_url, d.description as d_description, d.intended_volunteer_id as d_intended_volunteer_id, dv.id as dv_id, dv.user_id as dv_user_id, dv_u.full_name as dv_full_name, dv_u.phone as dv_phone, dv.skills as dv_skills FROM task_info t LEFT JOIN demand d ON t.demand_id = d.id LEFT JOIN volunteer_profile dv ON d.intended_volunteer_id = dv.id LEFT JOIN sys_user dv_u ON dv.user_id = dv_u.id WHERE t.status = 'PENDING'
AND t.task_type = #{taskType}
ORDER BY CASE t.priority WHEN 'URGENT' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'MEDIUM' THEN 3 ELSE 4 END, t.scheduled_date ASC

SELECT 
FROM task_info
WHERE volunteer_id = #{volunteerId}

  AND status = #{status}

ORDER BY scheduled_date DESC, created_time DESC

