UPDATE task_info
SET status = #{status}
WHERE id = #{id}

UPDATE task_info
SET status = 'COMPLETED',
    completed_time = NOW(),
    completion_note = #{completionNote}
WHERE id = #{id}

UPDATE task_info
SET status = 'APPROVED',
    rating = #{rating},
    feedback = #{feedback}
WHERE id = #{id}

